export const CAVEATS: Record<Insurer, string> = {
  AIA: 'Estimate (model reproduces AIA illustrations to ~0.5%).',
  GE: 'Estimate (~0.5% at quoted ages).',
  Allianz: 'Estimate. Male ages 46-60 are extrapolated (Allianz quoted males only to 45) - wider uncertainty.',
  HLA: 'Estimate (~0.5%). Package also bundles a TPD lump-sum rider + two payor riders.',
};

const alloc = (t: number, a100: number) => (t <= 3 ? 0.6 : t <= 6 ? 0.8 : t < a100 ? 0.95 : 1.0);

function llin(tbl: Tbl, a: number): number {
  const ks = Object.keys(tbl).map(Number).sort((x, y) => x - y);
  if (tbl[a] !== undefined) return tbl[a];
  const below = ks.filter((x) => x < a), above = ks.filter((x) => x > a);
  if (above.length === 0) {
    const x1 = ks[ks.length - 2], x2 = ks[ks.length - 1];
    if (tbl[x1] <= 0 || tbl[x2] <= 0) { const g = (tbl[x2] - tbl[x1]) / (x2 - x1); return Math.max(tbl[x2] + g * (a - x2), 0); }
    const g = (Math.log(tbl[x2]) - Math.log(tbl[x1])) / (x2 - x1); return tbl[x2] * Math.exp(g * (a - x2));
  }
  if (below.length === 0) return tbl[ks[0]];
  const lo = Math.max(...below), hi = Math.min(...above), f = (a - lo) / (hi - lo);
  if (tbl[lo] <= 0 || tbl[hi] <= 0) return tbl[lo] * (1 - f) + tbl[hi] * f;
  return Math.exp(Math.log(tbl[lo]) * (1 - f) + Math.log(tbl[hi]) * f);
}
function stepx(tbl: Tbl, a: number): number {
  const ks = Object.keys(tbl).map(Number).sort((x, y) => x - y);
  if (a <= ks[ks.length - 1]) { const below = ks.filter((x) => x <= a); return tbl[Math.max(...below)]; }
  const x1 = ks[ks.length - 2], x2 = ks[ks.length - 1];
  const g = (Math.log(tbl[x2]) - Math.log(tbl[x1])) / (x2 - x1); return tbl[x2] * Math.exp(g * (a - x2));
}
function corr(cc: Record<string, number>, age: number): number {
  const ks = Object.keys(cc).map(Number).sort((x, y) => x - y);
  if (age <= ks[0]) return cc[ks[0]];
  if (age >= ks[ks.length - 1]) return cc[ks[ks.length - 1]];
  const lo = Math.max(...ks.filter((x) => x <= age)), hi = Math.min(...ks.filter((x) => x >= age));
  if (lo === hi) return cc[lo];
  const f = (age - lo) / (hi - lo); return cc[lo] * (1 - f) + cc[hi] * f;
}

export interface PremiumResult { insurer: Insurer; product: string; annual: number; monthly: number; caveat: string; verified: boolean; }

// Verified official quotes (cross-checked against the insurer's own system). When the FA's
// inputs match an anchor exactly, the calculator returns the confirmed figure instead of the
// model estimate. Add rows here as quotes are verified.
interface Anchor { insurer: Insurer; gender: Gender; smoker: boolean; age: number; lifeSA: number; ciSA: number; monthly: number; }
const VERIFIED_ANCHORS: Anchor[] = [
  { insurer: 'Allianz', gender: 'M', smoker: false, age: 33, lifeSA: 80000, ciSA: 50000, monthly: 517 },
];

export function estimate(
  insurer: Insurer, age: number, gender: Gender, smoker: boolean,
  lifeSA = 100000, ciSA = 100000,
): PremiumResult | null {
  const d = DATA[insurer]; const key = gender + (smoker ? 'S' : 'N'); const T = d.master[key];
  if (!T || age < 1 || age > 75) return null;
  const anc = VERIFIED_ANCHORS.find((a) => a.insurer === insurer && a.gender === gender && a.smoker === smoker && a.age === age && a.lifeSA === lifeSA && a.ciSA === ciSA);
  if (anc) return { insurer, product: PRODUCT_NAME[insurer], annual: anc.monthly * 12, monthly: anc.monthly, caveat: 'Verified official quote.', verified: true };
  const n = 80 - age; let lo = 200, hi = 400000;
  for (let it = 0; it < 50; it++) {
    const P = (lo + hi) / 2; let AV = 0; const rm = Math.pow(1 + d.r, 1 / 12) - 1; let dead = false;
    for (let t = 1; t <= n; t++) {
      const a = age + t;
      const med = d.medBanded ? stepx(T.med, a) : llin(T.med, a);
      const cm = (llin(T.life, a) * (lifeSA / 1e5) + llin(T.ci, a) * (ciSA / 1e5) + med + llin(T.wvr, a) * P) / 12;
      const ap = (P * alloc(t, d.alloc100From)) / 12;
      for (let m = 0; m < 12; m++) { AV += ap; AV -= cm; AV -= d.service; AV -= AV * (d.fmc / 12); AV *= 1 + rm; }
      if (d.loyalty && t === 20) AV += 3 * P;
      if (AV < 0) { dead = true; break; }
    }
    if (dead) lo = P; else hi = P;
  }
  const P = (lo + hi) / 2; const annual = P * corr(d.corr[key], age);
  const monthly = Math.ceil(annual / 12); // round up to whole ringgit
  return { insurer, product: PRODUCT_NAME[insurer], annual: monthly * 12, monthly, caveat: CAVEATS[insurer], verified: false };
}

export function estimateAll(age: number, gender: Gender, smoker: boolean, lifeSA = 100000, ciSA = 100000): PremiumResult[] {
  return INSURERS.map((i) => estimate(i, age, gender, smoker, lifeSA, ciSA))
    .filter((r): r is PremiumResult => r !== null)
    .sort((a, b) => a.annual - b.annual);
}
